import os
import subprocess

class SimpleShell:
    def __init__(self):
        self.running = True

    def parse_command(self, command):
        """Parse user input into command and arguments"""
        parts = command.strip().split()
        if not parts:
            return None, []
        return parts[0], parts[1:]

    def execute_builtin(self, cmd, args):
        """Execute built-in shell commands"""
        if cmd == "exit":
            self.running = False
            return True
        elif cmd == "cd":
            if args:
                os.chdir(args[0])
            return True
        elif cmd == "pwd":
            print(os.getcwd())
            return True
        elif cmd == "ls":
            subprocess.run([cmd] + args)
            return True
        return False

    def run(self):
        """Main shell loop"""
        print("Simple Shell - Type 'exit' to quit")

        while self.running:
            command = input(f"{os.getcwd()}$ ")
            cmd, args = self.parse_command(command)

            if cmd:
                if not self.execute_builtin(cmd, args):
                    # Execute external commands
                    subprocess.run([cmd] + args)

if __name__ == "__main__":
    shell = SimpleShell()
    shell.run()

#include <stdio.h>
#include <unistd.h>
#include <sys/types.h>
#include <sys/sysinfo.h>

int main() {
    // Get process ID (system call)
    pid_t pid = getpid();
    printf("Process ID: %d\n", pid);

    // Get parent process ID (system call)
    pid_t ppid = getppid();
    printf("Parent Process ID: %d\n", ppid);

    // Get user ID (system call)
    uid_t uid = getuid();
    printf("User ID: %d\n", uid);

    // Get current working directory (system call)
    char cwd[256];
    if (getcwd(cwd, sizeof(cwd)) != NULL) {
        printf("Current Working Directory: %s\n", cwd);
    }

    // Get system information using sysinfo structure
    struct sysinfo si;
    sysinfo(&si);
    printf("Total Memory: %lu MB\n", si.totalram / (1024*1024));
    printf("Free Memory: %lu MB\n", si.freeram / (1024*1024));
    printf("Number of Processes: %d\n", si.procs);

    return 0;
}
